-- -----------------------------------------------------------------------------
-- Migration 098 -- Correct DHL zone and weight class data
--
-- Migration 088 inserted fallback rows with iso = 'GBR' (wrong; DC export uses
-- 2-letter 'GB').  zoneForPostcode now filters dc_zones by iso, so without GB
-- rows every UK DHL shipment resolved to Zone D (a GG/JE catch-all).
--
-- Steps:
--   1. Delete bad GBR rows from migration 088.
--   2. Upsert correct zone definitions (iso = GB/GG/JE) from DC export.
--   3. Upsert single Parcel weight class (0-30 kg) for each DHL service.
-- -----------------------------------------------------------------------------

BEGIN;

-- Step 1: Remove bad GBR rows from migration 088
DELETE FROM dc_zones
WHERE courier_code IN ('DHL','DHLC2C')
  AND iso = 'GBR';

-- Step 2: Upsert correct DHL zone definitions
INSERT INTO dc_zones
  (dc_zone_id, zone_name, courier_code, service_code, service_name,
   iso, included_postcodes, excluded_postcodes)
